     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→  <meta charset="UTF-8">
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→  <title>Job Board - Rekrut AI</title>
     7→  <link rel="preconnect" href="https://fonts.googleapis.com">
     8→  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
     9→  <link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@400;500;600&display=swap" rel="stylesheet">
    10→  <link rel="stylesheet" href="/css/styles.css">
    11→  <link rel="stylesheet" href="/css/responsive.css">
    12→  <link rel="stylesheet" href="/css/dashboard.css">
    13→</head>
    14→<body>
    15→  <div class="dashboard-layout">
    16→    <!-- Sidebar -->
    17→    <aside class="sidebar">
    18→      <a href="/" class="logo">
    19→        <span class="logo-icon">◎</span>
    20→        <span>Rekrut AI</span>
    21→      </a>
    22→
    23→      <nav class="sidebar-nav">
    24→        <a href="/candidate-dashboard.html" class="nav-item">
    25→          <span class="nav-icon">🏠</span>
    26→          <span>Dashboard</span>
    27→        </a>
    28→        <a href="/candidate-profile.html" class="nav-item">
    29→          <span class="nav-icon">👤</span>
    30→          <span>My Profile</span>
    31→        </a>
    32→        <a href="/omniscore.html" class="nav-item">
    33→          <span class="nav-icon">🎯</span>
    34→          <span>OmniScore</span>
    35→        </a>
    36→        <a href="/skill-assessments.html" class="nav-item">
    37→          <span class="nav-icon">📝</span>
    38→          <span>Skill Tests</span>
    39→        </a>
    40→        <a href="/interview.html" class="nav-item">
    41→          <span class="nav-icon">🎤</span>
    42→          <span>Interview Prep</span>
    43→        </a>
    44→        <a href="/job-board.html" class="nav-item active">
    45→          <span class="nav-icon">💼</span>
    46→          <span>Job Board</span>
    47→        </a>
    48→      </nav>
    49→
    50→      <div class="sidebar-footer">
    51→        <button onclick="handleLogout()" class="btn btn-ghost btn-sm btn-full">Logout</button>
    52→      </div>
    53→    </aside>
    54→
    55→    <!-- Main Content -->
    56→    <main class="main-content">
    57→      <header class="page-header">
    58→        <div>
    59→          <h1>Job Board</h1>
    60→          <p>Jobs matched to your OmniScore and skills</p>
    61→        </div>
    62→        <div class="header-stats">
    63→          <div class="mini-score">
    64→            <span class="mini-score-value" id="user-omniscore">---</span>
    65→            <span class="mini-score-label">Your OmniScore</span>
    66→          </div>
    67→        </div>
    68→      </header>
    69→
    70→      <!-- Tabs -->
    71→      <div class="job-tabs">
    72→        <button class="tab-btn active" data-tab="recommended" onclick="switchTab('recommended')">
    73→          <span>🎯</span> Recommended
    74→        </button>
    75→        <button class="tab-btn" data-tab="all" onclick="switchTab('all')">
    76→          <span>📋</span> All Jobs
    77→        </button>
    78→        <button class="tab-btn" data-tab="saved" onclick="switchTab('saved')">
    79→          <span>❤️</span> Saved <span class="tab-count" id="saved-count">0</span>
    80→        </button>
    81→        <button class="tab-btn" data-tab="applications" onclick="switchTab('applications')">
    82→          <span>📄</span> Applied <span class="tab-count" id="applied-count">0</span>
    83→        </button>
    84→      </div>
    85→
    86→      <!-- Filters (for recommended/all) -->
    87→      <div class="job-filters" id="job-filters">
    88→        <div class="filter-group">
    89→          <label>Location</label>
    90→          <select id="filter-location" onchange="applyFilters()">
    91→            <option value="">All Locations</option>
    92→            <option value="remote">Remote</option>
    93→            <option value="san francisco">San Francisco</option>
    94→            <option value="new york">New York</option>
    95→            <option value="austin">Austin</option>
    96→            <option value="seattle">Seattle</option>
    97→          </select>
    98→        </div>
    99→        <div class="filter-group">
   100→          <label>Job Type</label>
   101→          <select id="filter-type" onchange="applyFilters()">
   102→            <option value="">All Types</option>
   103→            <option value="full-time">Full-time</option>
   104→            <option value="part-time">Part-time</option>
   105→            <option value="contract">Contract</option>
   106→            <option value="internship">Internship</option>
   107→          </select>
   108→        </div>
   109→        <div class="filter-group">
   110→          <label>Match Score</label>
   111→          <select id="filter-match" onchange="applyFilters()">
   112→            <option value="">Any Match</option>
   113→            <option value="80">80%+ (Excellent)</option>
   114→            <option value="60">60%+ (Good)</option>
   115→            <option value="40">40%+ (Fair)</option>
   116→          </select>
   117→        </div>
   118→      </div>
   119→
   120→      <!-- Job Listings -->
   121→      <div class="jobs-container" id="jobs-container">
   122→        <div class="loading-state">
   123→          <div class="spinner"></div>
   124→          <p>Finding jobs for you...</p>
   125→        </div>
   126→      </div>
   127→
   128→      <!-- Job Detail Modal -->
   129→      <div class="job-detail-panel" id="job-detail-panel">
   130→        <div class="job-detail-content" id="job-detail-content">
   131→          <!-- Job details rendered here -->
   132→        </div>
   133→      </div>
   134→    </main>
   135→  </div>
   136→
   137→  <!-- Application Modal -->
   138→  <div class="modal-overlay" id="modal-overlay" onclick="closeModal()"></div>
   139→  <div class="modal" id="apply-modal">
   140→    <div class="modal-header">
   141→      <h3>Apply to <span id="apply-job-title"></span></h3>
   142→      <button class="modal-close" onclick="closeModal()">&times;</button>
   143→    </div>
   144→    <div class="modal-body">
   145→      <div class="apply-match-preview">
   146→        <div class="match-circle" id="apply-match-circle">
   147→          <span id="apply-match-score">0%</span>
   148→        </div>
   149→        <div class="match-info">
   150→          <span class="match-level" id="apply-match-level">Good Match</span>
   151→          <span class="match-desc" id="apply-match-desc">Based on your skills and experience</span>
   152→        </div>
   153→      </div>
   154→
   155→      <!-- Screening Questions (dynamically populated) -->
   156→      <div id="screening-questions-area" style="display: none;">
   157→        <div style="font-weight: 600; margin-bottom: 12px; font-size: 15px;">📋 Pre-Screening Questions</div>
   158→        <div id="screening-questions-form"></div>
   159→      </div>
   160→
   161→      <div class="form-group">
   162→        <label>Cover Letter (Optional)</label>
   163→        <textarea id="cover-letter" rows="6" placeholder="Tell them why you're a great fit for this role..."></textarea>
   164→      </div>
   165→
   166→      <div class="apply-checklist">
   167→        <h4>Your Application Includes:</h4>
   168→        <ul>
   169→          <li><span class="check">✓</span> Your OmniScore</li>
   170→          <li><span class="check">✓</span> Profile & Experience</li>
   171→          <li><span class="check">✓</span> Skills & Assessments</li>
   172→          <li><span class="check" id="resume-check">✓</span> Resume (if uploaded)</li>
   173→        </ul>
   174→      </div>
   175→    </div>
   176→    <div class="modal-footer">
   177→      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
   178→      <button class="btn btn-primary" id="submit-apply-btn" onclick="submitApplication()">Submit Application</button>
   179→    </div>
   180→  </div>
   181→
   182→  <script src="/js/main.js"></script>
   183→  <script>
   184→    let allJobs = [];
   185→    let savedJobs = [];
   186→    let applications = [];
   187→    let currentTab = 'recommended';
   188→    let selectedJobId = null;
   189→
   190→    document.addEventListener('DOMContentLoaded', async () => {
   191→      const user = await checkAuth();
   192→      if (!user) {
   193→        window.location.href = '/login.html';
   194→        return;
   195→      }
   196→
   197→      loadOmniScore();
   198→      loadJobs();
   199→      loadSavedJobs();
   200→      loadApplications();
   201→    });
   202→
   203→    async function loadOmniScore() {
   204→      try {
   205→        const data = await apiCall('/omniscore');
   206→        if (data.success && data.omniscore) {
   207→          document.getElementById('user-omniscore').textContent = data.omniscore.total_score;
   208→        }
   209→      } catch (err) {
   210→        document.getElementById('user-omniscore').textContent = '300';
   211→      }
   212→    }
   213→
   214→    async function loadJobs() {
   215→      try {
   216→        const data = await apiCall('/candidate/jobs/recommended?limit=30');
   217→        if (data.success) {
   218→          allJobs = data.jobs;
   219→          renderJobs(data.jobs);
   220→        }
   221→      } catch (err) {
   222→        console.error('Load jobs error:', err);
   223→        document.getElementById('jobs-container').innerHTML = `
   224→          <div class="empty-state">
   225→            <p>Could not load jobs. Please try again.</p>
   226→          </div>
   227→        `;
   228→      }
   229→    }
   230→
   231→    async function loadSavedJobs() {
   232→      try {
   233→        const data = await apiCall('/candidate/jobs/saved');
   234→        if (data.success) {
   235→          savedJobs = data.jobs;
   236→          document.getElementById('saved-count').textContent = data.jobs.length;
   237→        }
   238→      } catch (err) {
   239→        console.error('Load saved jobs error:', err);
   240→      }
   241→    }
   242→
   243→    async function loadApplications() {
   244→      try {
   245→        const data = await apiCall('/candidate/applications');
   246→        if (data.success) {
   247→          applications = data.applications;
   248→          document.getElementById('applied-count').textContent = data.applications.length;
   249→        }
   250→      } catch (err) {
   251→        console.error('Load applications error:', err);
   252→      }
   253→    }
   254→
   255→    function switchTab(tab) {
   256→      currentTab = tab;
   257→
   258→      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
   259→      document.querySelector(`[data-tab="${tab}"]`).classList.add('active');
   260→
   261→      // Show/hide filters
   262→      document.getElementById('job-filters').style.display =
   263→        (tab === 'recommended' || tab === 'all') ? 'flex' : 'none';
   264→
   265→      // Close detail panel
   266→      document.getElementById('job-detail-panel').classList.remove('active');
   267→
   268→      // Render appropriate list
   269→      if (tab === 'recommended') {
   270→        renderJobs(allJobs);
   271→      } else if (tab === 'all') {
   272→        // For all, we show the same but without match info prominently
   273→        renderJobs(allJobs, false);
   274→      } else if (tab === 'saved') {
   275→        renderSavedJobs();
   276→      } else if (tab === 'applications') {
   277→        renderApplications();
   278→      }
   279→    }
   280→
   281→    function applyFilters() {
   282→      const location = document.getElementById('filter-location').value.toLowerCase();
   283→      const type = document.getElementById('filter-type').value;
   284→      const minMatch = parseInt(document.getElementById('filter-match').value) || 0;
   285→
   286→      let filtered = allJobs.filter(job => {
   287→        if (location && job.location && !job.location.toLowerCase().includes(location)) return false;
   288→        if (type && job.job_type !== type) return false;
   289→        if (minMatch && (!job.match || job.match.match_score < minMatch)) return false;
   290→        return true;
   291→      });
   292→
   293→      renderJobs(filtered);
   294→    }
   295→
   296→    function renderJobs(jobs, showMatch = true) {
   297→      const container = document.getElementById('jobs-container');
   298→
   299→      if (!jobs || jobs.length === 0) {
   300→        container.innerHTML = `
   301→          <div class="empty-state">
   302→            <p>No jobs found matching your criteria.</p>
   303→          </div>
   304→        `;
   305→        return;
   306→      }
   307→
   308→      container.innerHTML = `
   309→        <div class="jobs-list">
   310→          ${jobs.map(job => renderJobCard(job, showMatch)).join('')}
   311→        </div>
   312→      `;
   313→    }
   314→
   315→    function renderJobCard(job, showMatch = true) {
   316→      const match = job.match || {};
   317→      const matchScore = match.match_score || 50;
   318→      const matchLevel = match.match_level || 'fair';
   319→      const isSaved = savedJobs.some(s => s.id === job.id);
   320→      const hasApplied = applications.some(a => a.job_id === job.id);
   321→
   322→      return `
   323→        <div class="job-card ${hasApplied ? 'applied' : ''}" onclick="showJobDetail(${job.id})">
   324→          <div class="job-card-main">
   325→            <div class="job-card-header">
   326→              <h3>${job.title}</h3>
   327→              <button class="save-btn ${isSaved ? 'saved' : ''}" onclick="event.stopPropagation(); toggleSave(${job.id})">
   328→                ${isSaved ? '❤️' : '🤍'}
   329→              </button>
   330→            </div>
   331→            <p class="job-company">${job.company || job.posted_by_company || 'Company'}</p>
   332→            <div class="job-meta">
   333→              ${job.location ? `<span class="job-location">📍 ${job.location}</span>` : ''}
   334→              ${job.job_type ? `<span class="job-type">${job.job_type}</span>` : ''}
   335→              ${job.salary_range ? `<span class="job-salary">💰 ${job.salary_range}</span>` : ''}
   336→            </div>
   337→          </div>
   338→          ${showMatch ? `
   339→            <div class="job-card-match">
   340→              <div class="match-indicator ${matchLevel}">
   341→                <span class="match-percent">${matchScore}%</span>
   342→                <span class="match-label">match</span>
   343→              </div>
   344→              ${hasApplied ? '<span class="applied-badge">Applied</span>' : ''}
   345→            </div>
   346→          ` : ''}
   347→        </div>
   348→      `;
   349→    }
   350→
   351→    function renderSavedJobs() {
   352→      const container = document.getElementById('jobs-container');
   353→
   354→      if (savedJobs.length === 0) {
   355→        container.innerHTML = `
   356→          <div class="empty-state">
   357→            <h3>No Saved Jobs</h3>
   358→            <p>Save jobs you're interested in to apply later.</p>
   359→            <button class="btn btn-primary" onclick="switchTab('recommended')">Browse Jobs</button>
   360→          </div>
   361→        `;
   362→        return;
   363→      }
   364→
   365→      container.innerHTML = `
   366→        <div class="jobs-list">
   367→          ${savedJobs.map(job => renderJobCard(job, true)).join('')}
   368→        </div>
   369→      `;
   370→    }
   371→
   372→    function renderApplications() {
   373→      const container = document.getElementById('jobs-container');
   374→
   375→      if (applications.length === 0) {
   376→        container.innerHTML = `
   377→          <div class="empty-state">
   378→            <h3>No Applications Yet</h3>
   379→            <p>Apply to jobs to track your applications here.</p>
   380→            <button class="btn btn-primary" onclick="switchTab('recommended')">Find Jobs</button>
   381→          </div>
   382→        `;
   383→        return;
   384→      }
   385→
   386→      container.innerHTML = `
   387→        <div class="applications-list">
   388→          ${applications.map(app => `
   389→            <div class="application-card" onclick="showJobDetail(${app.job_id})">
   390→              <div class="application-info">
   391→                <h4>${app.title}</h4>
   392→                <p>${app.company || app.posted_by_company || 'Company'}</p>
   393→                <span class="application-date">Applied ${formatDate(app.applied_at)}</span>
   394→              </div>
   395→              <div class="application-status">
   396→                <span class="status-badge ${app.status}">${formatStatus(app.status)}</span>
   397→                ${app.match_score ? `<span class="match-score">${app.match_score}% match</span>` : ''}
   398→              </div>
   399→            </div>
   400→          `).join('')}
   401→        </div>
   402→      `;
   403→    }
   404→
   405→    function formatDate(dateStr) {
   406→      const date = new Date(dateStr);
   407→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
   408→    }
   409→
   410→    function formatStatus(status) {
   411→      const labels = {
   412→        'applied': 'Applied',
   413→        'reviewing': 'Under Review',
   414→        'interviewing': 'Interviewing',
   415→        'offered': 'Offer Received',
   416→        'rejected': 'Not Selected',
   417→        'accepted': 'Accepted'
   418→      };
   419→      return labels[status] || status;
   420→    }
   421→
   422→    async function showJobDetail(jobId) {
   423→      selectedJobId = jobId;
   424→      const job = allJobs.find(j => j.id === jobId) ||
   425→                  savedJobs.find(j => j.id === jobId) ||
   426→                  applications.find(a => a.job_id === jobId);
   427→
   428→      if (!job) return;
   429→
   430→      const match = job.match || {};
   431→      const isSaved = savedJobs.some(s => s.id === jobId);
   432→      const hasApplied = applications.some(a => a.job_id === jobId);
   433→
   434→      const panel = document.getElementById('job-detail-panel');
   435→      const content = document.getElementById('job-detail-content');
   436→
   437→      content.innerHTML = `
   438→        <button class="close-panel-btn" onclick="closeDetailPanel()">×</button>
   439→
   440→        <div class="job-detail-header">
   441→          <h2>${job.title}</h2>
   442→          <p class="detail-company">${job.company || job.posted_by_company || 'Company'}</p>
   443→        </div>
   444→
   445→        <div class="job-detail-meta">
   446→          ${job.location ? `<span>📍 ${job.location}</span>` : ''}
   447→          ${job.job_type ? `<span>⏰ ${job.job_type}</span>` : ''}
   448→          ${job.salary_range ? `<span>💰 ${job.salary_range}</span>` : ''}
   449→        </div>
   450→
   451→        ${match.match_score ? `
   452→          <div class="job-match-card ${match.match_level}">
   453→            <div class="match-header">
   454→              <span class="match-big-score">${match.match_score}%</span>
   455→              <span class="match-big-label">${match.match_level} match</span>
   456→            </div>
   457→            ${match.recommendation ? `<p class="match-recommendation">${match.recommendation}</p>` : ''}
   458→            ${match.matching_skills && match.matching_skills.length > 0 ? `
   459→              <div class="match-skills">
   460→                <strong>Matching Skills:</strong>
   461→                <div class="skill-chips">
   462→                  ${match.matching_skills.map(s => `<span class="skill-chip match">${s}</span>`).join('')}
   463→                </div>
   464→              </div>
   465→            ` : ''}
   466→            ${match.missing_skills && match.missing_skills.length > 0 ? `
   467→              <div class="match-skills">
   468→                <strong>Skills to Develop:</strong>
   469→                <div class="skill-chips">
   470→                  ${match.missing_skills.map(s => `<span class="skill-chip missing">${s}</span>`).join('')}
   471→                </div>
   472→              </div>
   473→            ` : ''}
   474→          </div>
   475→        ` : ''}
   476→
   477→        <div class="job-detail-section">
   478→          <h3>Description</h3>
   479→          <div class="job-description">${job.description || 'No description provided.'}</div>
   480→        </div>
   481→
   482→        ${job.requirements ? `
   483→          <div class="job-detail-section">
   484→            <h3>Requirements</h3>
   485→            <div class="job-requirements">${job.requirements}</div>
   486→          </div>
   487→        ` : ''}
   488→
   489→        <div class="job-detail-actions">
   490→          <button class="btn btn-ghost" onclick="toggleSave(${jobId})">
   491→            ${isSaved ? '❤️ Saved' : '🤍 Save'}
   492→          </button>
   493→          ${hasApplied ? `
   494→            <button class="btn btn-primary" disabled>Applied ✓</button>
   495→          ` : `
   496→            <button class="btn btn-primary" onclick="showApplyModal(${jobId})">Apply Now</button>
   497→          `}
   498→        </div>
   499→
   500→        <div class="job-detail-footer">
   501→          <span>Posted ${formatDate(job.created_at)}</span>
   502→        </div>
   503→      `;
   504→
   505→      panel.classList.add('active');
   506→    }
   507→
   508→    function closeDetailPanel() {
   509→      document.getElementById('job-detail-panel').classList.remove('active');
   510→    }
   511→
   512→    async function toggleSave(jobId) {
   513→      const isSaved = savedJobs.some(s => s.id === jobId);
   514→
   515→      try {
   516→        if (isSaved) {
   517→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'DELETE' });
   518→          savedJobs = savedJobs.filter(s => s.id !== jobId);
   519→        } else {
   520→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'POST' });
   521→          const job = allJobs.find(j => j.id === jobId);
   522→          if (job) savedJobs.push(job);
   523→        }
   524→
   525→        document.getElementById('saved-count').textContent = savedJobs.length;
   526→
   527→        // Re-render current view
   528→        if (currentTab === 'saved') {
   529→          renderSavedJobs();
   530→        } else {
   531→          renderJobs(allJobs);
   532→        }
   533→
   534→        // Update detail panel if open
   535→        if (selectedJobId === jobId) {
   536→          showJobDetail(jobId);
   537→        }
   538→      } catch (err) {
   539→        console.error('Toggle save error:', err);
   540→      }
   541→    }
   542→
   543→    function showApplyModal(jobId) {
   544→      selectedJobId = jobId;
   545→      const job = allJobs.find(j => j.id === jobId) || savedJobs.find(j => j.id === jobId);
   546→
   547→      if (!job) return;
   548→
   549→      const match = job.match || {};
   550→
   551→      document.getElementById('apply-job-title').textContent = job.title;
   552→      document.getElementById('apply-match-score').textContent = (match.match_score || 50) + '%';
   553→      document.getElementById('apply-match-level').textContent =
   554→        (match.match_level || 'fair').charAt(0).toUpperCase() + (match.match_level || 'fair').slice(1) + ' Match';
   555→      document.getElementById('apply-match-desc').textContent = 'Based on your skills and OmniScore';
   556→
   557→      const circle = document.getElementById('apply-match-circle');
   558→      circle.className = 'match-circle ' + (match.match_level || 'fair');
   559→
   560→      document.getElementById('cover-letter').value = '';
   561→
   562→      // Render screening questions
   563→      const sqArea = document.getElementById('screening-questions-area');
   564→      const sqForm = document.getElementById('screening-questions-form');
   565→      const questions = job.screening_questions || [];
   566→
   567→      if (questions.length > 0) {
   568→        sqArea.style.display = 'block';
   569→        sqForm.innerHTML = questions.map(q => {
   570→          const reqTag = q.required ? '<span style="color: #ef4444;">*</span>' : '';
   571→          let inputHTML = '';
   572→
   573→          if (q.type === 'yes_no') {
   574→            inputHTML = `
   575→              <div class="sq-answer-options">
   576→                <label class="sq-radio"><input type="radio" name="sq_${q.id}" value="yes" ${q.required ? 'required' : ''}> Yes</label>
   577→                <label class="sq-radio"><input type="radio" name="sq_${q.id}" value="no"> No</label>
   578→              </div>`;
   579→          } else if (q.type === 'select') {
   580→            inputHTML = `<select class="sq-input" id="sq_${q.id}" ${q.required ? 'required' : ''}>
   581→              <option value="">Select...</option>
   582→              ${(q.options || []).map(o => `<option value="${o}">${o}</option>`).join('')}
   583→            </select>`;
   584→          } else if (q.type === 'number') {
   585→            inputHTML = `<input type="number" class="sq-input" id="sq_${q.id}" placeholder="${q.placeholder || ''}" ${q.required ? 'required' : ''}>`;
   586→          } else {
   587→            inputHTML = `<input type="text" class="sq-input" id="sq_${q.id}" placeholder="${q.placeholder || 'Your answer...'}" ${q.required ? 'required' : ''}>`;
   588→          }
   589→
   590→          return `
   591→            <div class="sq-field" style="margin-bottom: 16px;">
   592→              <label style="font-size: 14px; font-weight: 500; display: block; margin-bottom: 6px;">${q.question} ${reqTag}</label>
   593→              ${inputHTML}
   594→            </div>`;
   595→        }).join('');
   596→      } else {
   597→        sqArea.style.display = 'none';
   598→        sqForm.innerHTML = '';
   599→      }
   600→
   601→      showModal();
   602→    }
   603→
   604→    function showModal() {
   605→      document.getElementById('modal-overlay').classList.add('active');
   606→      document.getElementById('apply-modal').classList.add('active');
   607→    }
   608→
   609→    function closeModal() {
   610→      document.getElementById('modal-overlay').classList.remove('active');
   611→      document.getElementById('apply-modal').classList.remove('active');
   612→    }
   613→
   614→    async function submitApplication() {
   615→      const coverLetter = document.getElementById('cover-letter').value;
   616→      const btn = document.getElementById('submit-apply-btn');
   617→
   618→      // Collect screening answers
   619→      const job = allJobs.find(j => j.id === selectedJobId) || savedJobs.find(j => j.id === selectedJobId);
   620→      const questions = (job && job.screening_questions) || [];
   621→      const screening_answers = {};
   622→
   623→      for (const q of questions) {
   624→        let val;
   625→        if (q.type === 'yes_no') {
   626→          const checked = document.querySelector(`input[name="sq_${q.id}"]:checked`);
   627→          val = checked ? checked.value : '';
   628→        } else {
   629→          const el = document.getElementById(`sq_${q.id}`);
   630→          val = el ? el.value.trim() : '';
   631→        }
   632→
   633→        if (q.required && !val) {
   634→          alert(`Please answer: "${q.question}"`);
   635→          return;
   636→        }
   637→        screening_answers[q.id] = val;
   638→      }
   639→
   640→      btn.textContent = 'Submitting...';
   641→      btn.disabled = true;
   642→
   643→      try {
   644→        const data = await apiCall(`/candidate/jobs/${selectedJobId}/apply`, {
   645→          method: 'POST',
   646→          body: JSON.stringify({ cover_letter: coverLetter, screening_answers })
   647→        });
   648→
   649→        if (data.success) {
   650→          closeModal();
   651→          applications.push(data.application);
   652→          document.getElementById('applied-count').textContent = applications.length;
   653→
   654→          // Re-render and show success
   655→          if (currentTab === 'recommended' || currentTab === 'all') {
   656→            renderJobs(allJobs);
   657→          }
   658→
   659→          // Update detail panel
   660→          showJobDetail(selectedJobId);
   661→
   662→          alert('Application submitted successfully! 🎉');
   663→        }
   664→      } catch (err) {
   665→        console.error('Apply error:', err);
   666→        alert('Failed to submit application. Please try again.');
   667→      } finally {
   668→        btn.textContent = 'Submit Application';
   669→        btn.disabled = false;
   670→      }
   671→    }
   672→  </script>
