   403→    function formatDate(dateStr) {
   404→      const date = new Date(dateStr);
   405→      const now = new Date();
   406→      const diff = now - date;
   407→      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   408→      if (days === 0) return 'Today';
   409→      if (days === 1) return 'Yesterday';
   410→      if (days < 7) return `${days} days ago`;
   411→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
   412→    }
