   332→          edu.institution,
   333→          edu.degree,
   334→          edu.field,
   335→          edu.start_date ? new Date(edu.start_date + '-01-01') : null,
   336→          edu.end_date && edu.end_date !== 'Present' ? new Date(edu.end_date + '-01-01') : null,
   337→          edu.gpa,
   338→          JSON.stringify(edu.achievements || []),
   339→          i
   340→        ]);
   341→      }
   342→    }
   343→
   344→    // Apply skills
   345→    if (sections.includes('skills') && parsed_data.skills) {
