   243→// API helper with automatic token refresh
   244→async function apiCall(endpoint, options = {}) {
   245→  let token = localStorage.getItem(TOKEN_KEY);
   246→  const headers = {
   247→    'Content-Type': 'application/json',
   248→    ...(token && { 'Authorization': `Bearer ${token}` }),
   249→    ...options.headers
   250→  };
   251→
   252→  let response = await fetch(`/api${endpoint}`, {
   253→    ...options,
   254→    headers
   255→  });
   256→
   257→  // If 401 and we have a refresh token, try to refresh
   258→  if (response.status === 401) {
   259→    const newToken = await refreshAccessToken();
   260→    if (newToken) {
   261→      // Retry with new token
   262→      headers['Authorization'] = `Bearer ${newToken}`;
   263→      response = await fetch(`/api${endpoint}`, {
   264→        ...options,
   265→        headers
   266→      });
   267→    } else {
   268→      // Still unauthorized - redirect to login
   269→      window.location.href = '/login.html';
   270→      return null;
   271→    }
   272→  }
   273→
   274→  // Handle non-OK responses
   275→  if (!response.ok) {
   276→    const contentType = response.headers.get('content-type') || '';
   277→    if (contentType.includes('application/json')) {
   278→      const errorData = await response.json();
   279→      throw new Error(errorData.error || errorData.message || `API error: ${response.status}`);
   280→    }
   281→    throw new Error(`API error: ${response.status}`);
   282→  }
   283→
   284→  // Safely parse JSON (some endpoints may return non-JSON)
   285→  const contentType = response.headers.get('content-type') || '';
   286→  if (contentType.includes('application/json')) {
   287→    return response.json();
   288→  }
   289→  return { success: true };
   290→}
